(function () {
  if (window.THREE && window.THREE.Scene) {
    return;
  }

  import('/assets/vendor/three/three.module.min.js').then(module => {
    window.THREE = module;
    window.dispatchEvent(new CustomEvent('lq-three-ready'));
  }).catch(function (error) {
    console.error('Failed to load Three.js module for tech constellation.', error);
  });
})();
